const KEYWORDS = ['спартак', 'spartak', 'красно-белые'];
const CUTOFF_HOURS = 72;
const MAX_POSTS = 5;

const cutoff = new Date(Date.now() - CUTOFF_HOURS * 60 * 60 * 1000);

function getSource(link) {
  if ((link || '').includes('championat')) return 'Чемпионат';
  if ((link || '').includes('tass')) return 'ТАСС';
  return 'Новости';
}

const items = $input.all();
const filtered = [];

for (const item of items) {
  const title = item.json.title || '';
  const content = item.json.contentSnippet || item.json.content || item.json.summary || '';
  const combined = (title + ' ' + content).toLowerCase();

  if (!KEYWORDS.some(kw => combined.includes(kw))) continue;

  const pubDate = item.json.isoDate
    ? new Date(item.json.isoDate)
    : item.json.pubDate
      ? new Date(item.json.pubDate)
      : new Date();

  if (pubDate < cutoff) continue;

  filtered.push({
    title,
    link: item.json.link || item.json.guid || '',
    content,
    pubDate,
    sourceName: getSource(item.json.link),
  });
}

const seen = new Set();
const unique = filtered.filter(a => {
  const key = (a.link || a.title).substring(0, 80);
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

unique.sort((a, b) => a.pubDate - b.pubDate);
const toPost = unique.slice(0, MAX_POSTS);

if (toPost.length === 0) return [];

return toPost.map(a => {
  const timeStr = a.pubDate.toLocaleTimeString('ru-RU', {
    hour: '2-digit',
    minute: '2-digit',
    timeZone: 'Europe/Moscow',
  });

  const desc = a.content
    .replace(/<[^>]+>/g, '')
    .replace(/\s+/g, ' ')
    .trim()
    .substring(0, 500);

  let text = `🔴⚪️ <b>${a.title}</b>`;
  if (desc) text += `\n\n${desc}`;
  text += `\n\n📰 ${a.sourceName} | 🕐 ${timeStr} МСК`;

  return { json: { text } };
});
